package games.sparking.altara;

import games.sparking.altara.command.CommandService;
import games.sparking.altara.game.GameManager;
import net.kyori.adventure.text.Component;
import org.bukkit.plugin.java.JavaPlugin;

public class AltaraGames extends AltaraPaper {

    public AltaraGames(JavaPlugin instance) {
        super(instance);

        // Initialise the game framework (registry + player routing + disconnect handler)
        GameManager.init();

        registerCommands();
        registerListener();
        getPaperInstance().getServer().getConsoleSender().sendMessage(Component.text("Altara Games has booted"));
    }

    @Override
    public void registerCommands() {
        super.registerCommands();
        CommandService.register(AltaraPaper.getPaperInstance(),
                new GameCommand()
        );
    }
}

package games.sparking.altara;

import games.sparking.altara.command.CommandService;
import games.sparking.altara.game.GameManager;
import games.sparking.altara.game.games.bomblobbers.BombLobbers;
import net.kyori.adventure.text.Component;
import org.bukkit.plugin.java.JavaPlugin;

public class AltaraGames extends AltaraPaper {

    public AltaraGames(JavaPlugin instance) {
        super(instance);

        // Initialise the game framework (registry + player routing + disconnect handler)
        GameManager manager = GameManager.init();

        // ── Register game types ───────────────────────────────────────────
        manager.registerGameType("bomblobbers", BombLobbers::new);

        registerCommands();
        registerListener();
        getPaperInstance().getServer().getConsoleSender().sendMessage(Component.text("Altara Games has booted"));
    }

    @Override
    public void registerCommands() {
        super.registerCommands();
        CommandService.register(AltaraPaper.getPaperInstance(),
                new GameCommand()
        );
    }
}

package games.sparking.altara.game;

import games.sparking.altara.AltaraPaper;
import games.sparking.altara.game.event.*;
import games.sparking.altara.game.kit.KitManager;
import games.sparking.altara.world.AltaraWorld;
import games.sparking.altara.game.player.GamePlayer;
import games.sparking.altara.game.player.GamePlayerState;
import games.sparking.altara.game.team.GameTeam;
import lombok.Getter;
import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import org.bukkit.event.HandlerList;
import org.bukkit.event.Listener;
import org.bukkit.scheduler.BukkitTask;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.function.Consumer;
import java.util.stream.Collectors;

/**
 * Core abstract class for all game types on the Altara network.
 *
 * <h2>Multiple games, one server</h2>
 * Unlike a traditional single-game-per-server model, the Altara framework allows many
 * {@code Game} instances to run simultaneously on the same server.  Each instance is
 * isolated by its unique {@link #instanceId} and tracked by the {@link GameManager}.
 *
 * <h2>Lifecycle</h2>
 * {@link GameState#PreLoad} → {@link GameState#Loading} → {@link GameState#Recruit}
 * → {@link GameState#Prepare} → {@link GameState#Live} → {@link GameState#End}
 * → {@link GameState#Dead}
 *
 * <h2>Registering a game type</h2>
 * <pre>{@code
 * GameManager.getInstance().registerGameType("mygame", MyGame::new);
 * GameManager.getInstance().createGame("mygame");
 * }</pre>
 */
public abstract class Game implements Listener {

    // =========================================================================
    // Identity
    // =========================================================================

    /** Globally unique identifier for this game instance. */
    @Getter private final UUID instanceId = UUID.randomUUID();

    /**
     * Short 8-character ID for player-facing commands
     * (first 8 hex chars of the UUID, upper-cased).
     */
    @Getter private final String shortId = instanceId.toString().substring(0, 8).toUpperCase();

    // =========================================================================
    // State
    // =========================================================================

    @Getter private GameState state = GameState.PreLoad;

    /** Epoch millis when the game went {@link GameState#Live}, or {@code -1}. */
    @Getter private long startTime = -1;

    /** Epoch millis when the game went {@link GameState#End}, or {@code -1}. */
    @Getter private long endTime = -1;

    // =========================================================================
    // Players & Teams
    // =========================================================================

    /** All players currently in this game, keyed by {@link UUID}. */
    @Getter private final Map<UUID, GamePlayer> players = new ConcurrentHashMap<>();

    /** Teams registered for this game (populated during {@link #onStart()}). */
    @Getter private final List<GameTeam> teams = new ArrayList<>();

    // =========================================================================
    // Internal
    // =========================================================================

    private BukkitTask tickTask;

    /**
     * Manages kit registration, player kit selection, and the kit-selector GUI.
     * Access via {@link #getKitManager()} – it is lazily constructed on first access.
     */
    @Getter private final KitManager kitManager = new KitManager(this);

    // =========================================================================
    // Abstract metadata
    // =========================================================================

    public abstract String getName();
    public abstract String getDescription();
    public abstract int getMinPlayers();
    public abstract int getMaxPlayers();

    // =========================================================================
    // Lifecycle hooks
    // =========================================================================

    /** Called on {@link GameState#Loading}. Load world/arena here. */
    protected void onLoad() {}

    /** Called on {@link GameState#Recruit}. Set up lobby behaviours here. */
    protected void onRecruit() {}

    /** Called on {@link GameState#Prepare}. Run countdown, freeze players, etc. */
    protected void onPrepare() {}

    /** Called on {@link GameState#Live}. Give kits, assign teams, start logic. */
    protected abstract void onStart();

    /** Called on {@link GameState#End}. Announce results, schedule cleanup delay. */
    protected abstract void onEnd();

    /** Called on {@link GameState#Dead}. Release extra resources (e.g. delete world). */
    protected void onDead() {}

    /**
     * Called once per server tick while {@link GameState#Live}.
     * Override for continuous game logic (border shrinking, timer checks, etc.).
     */
    protected void onTick() {}

    /** Called after a player successfully joins this game. */
    protected void onPlayerJoin(GamePlayer gamePlayer) {}

    /** Called after a player has been removed from this game. */
    protected void onPlayerLeave(GamePlayer gamePlayer) {}

    // =========================================================================
    // Start condition
    // =========================================================================

    /**
     * Returns {@code true} when the game may transition to {@link GameState#Prepare}.
     * Default: player count >= {@link #getMinPlayers()}.
     */
    public boolean canStart() {
        return players.size() >= getMinPlayers();
    }

    // =========================================================================
    // State management
    // =========================================================================

    /**
     * Transitions the game to {@code newState}.
     * Fires {@link GameStateChangeEvent} first (cancellable).
     */
    public final void setState(GameState newState) {
        GameState oldState = this.state;
        if (oldState == newState) return;

        GameStateChangeEvent event = new GameStateChangeEvent(this, oldState, newState);
        Bukkit.getPluginManager().callEvent(event);
        if (event.isCancelled()) return;

        this.state = newState;

        switch (newState) {
            case Loading -> {
                Bukkit.getPluginManager().registerEvents(this, AltaraPaper.getPaperInstance());
                kitManager.initialize(); // register all kit + perk listeners
                onLoad();
            }
            case Recruit  -> onRecruit();
            case Prepare  -> onPrepare();
            case Live     -> {
                startTime = System.currentTimeMillis();
                onStart();
                Bukkit.getPluginManager().callEvent(new GameStartEvent(this));
                startTickLoop();
            }
            case End      -> {
                endTime = System.currentTimeMillis();
                stopTickLoop();
                onEnd();
                Bukkit.getPluginManager().callEvent(new GameEndEvent(this));
            }
            case Dead     -> {
                stopTickLoop();
                kitManager.cleanup();   // unregister kit + perk listeners
                HandlerList.unregisterAll(this);
                onDead();
                GameManager.getInstance().destroyGame(instanceId);
            }
        }
    }

    /** If {@link GameState#Live}, transitions to {@link GameState#End}. */
    protected final void endGame() {
        if (state == GameState.Live) setState(GameState.End);
    }

    /** Transitions this instance to {@link GameState#Dead}, triggering full cleanup. */
    public final void destroy() {
        if (state != GameState.Dead) setState(GameState.Dead);
    }

    // =========================================================================
    // Tick loop
    // =========================================================================

    private void startTickLoop() {
        if (tickTask != null) return;
        tickTask = Bukkit.getScheduler().runTaskTimer(
                AltaraPaper.getPaperInstance(),
                () -> { if (state == GameState.Live) onTick(); },
                0L, 1L
        );
    }

    private void stopTickLoop() {
        if (tickTask != null) { tickTask.cancel(); tickTask = null; }
    }

    // =========================================================================
    // Player management
    // =========================================================================

    /**
     * Adds a player to this game.
     * Fails if the player is already in a game, this game is full,
     * or a {@link PlayerJoinGameEvent} listener cancels the join.
     *
     * @return {@code true} on success
     */
    public final boolean addPlayer(Player player) {
        if (players.containsKey(player.getUniqueId())) return false;
        if (players.size() >= getMaxPlayers()) return false;
        if (GameManager.getInstance().getPlayerGame(player) != null) return false;

        GamePlayer gamePlayer = new GamePlayer(player, this);

        PlayerJoinGameEvent event = new PlayerJoinGameEvent(this, gamePlayer);
        Bukkit.getPluginManager().callEvent(event);
        if (event.isCancelled()) return false;

        players.put(player.getUniqueId(), gamePlayer);
        GameManager.getInstance().registerPlayerGame(player, this);
        onPlayerJoin(gamePlayer);
        return true;
    }

    /**
     * Removes a player from this game.
     *
     * @return {@code true} if the player was in this game and was removed
     */
    public final boolean removePlayer(Player player) {
        GamePlayer gamePlayer = players.remove(player.getUniqueId());
        if (gamePlayer == null) return false;

        teams.forEach(team -> team.removePlayer(player));
        GameManager.getInstance().unregisterPlayerGame(player);

        Bukkit.getPluginManager().callEvent(new PlayerLeaveGameEvent(this, gamePlayer));
        onPlayerLeave(gamePlayer);
        return true;
    }

    public boolean hasPlayer(Player player) {
        return players.containsKey(player.getUniqueId());
    }

    public Optional<GamePlayer> getGamePlayer(Player player) {
        return Optional.ofNullable(players.get(player.getUniqueId()));
    }

    /** All online players whose state is {@link GamePlayerState#ALIVE}. */
    public List<Player> getAlivePlayers() {
        return players.values().stream()
                .filter(GamePlayer::isAlive)
                .map(GamePlayer::getPlayer)
                .filter(Objects::nonNull)
                .collect(Collectors.toList());
    }

    public long getAliveCount() {
        return players.values().stream().filter(GamePlayer::isAlive).count();
    }

    // =========================================================================
    // Team management
    // =========================================================================

    /** Registers a team and returns it (for chaining). */
    public GameTeam addTeam(GameTeam team) {
        teams.add(team);
        return team;
    }

    public Optional<GameTeam> getTeamOf(Player player) {
        return teams.stream().filter(t -> t.hasPlayer(player)).findFirst();
    }

    // =========================================================================
    // Messaging
    // =========================================================================

    /** Sends a message to every online player in this game. */
    public void broadcast(String message) {
        players.values().forEach(gp -> gp.sendMessage(message));
    }

    public void forEachPlayer(Consumer<GamePlayer> action) {
        players.values().forEach(action);
    }

    // =========================================================================
    // Convenience state queries
    // =========================================================================

    public boolean isLive()       { return state == GameState.Live; }
    public boolean isRecruiting() { return state == GameState.Recruit; }
    public boolean isPreparing()  { return state == GameState.Prepare; }
    public boolean hasEnded()     { return state == GameState.End || state == GameState.Dead; }

    @Override
    public String toString() {
        return getName() + "#" + shortId + "[" + state + ", players=" + players.size() + "]";
    }
}

package games.sparking.altara.game;

import games.sparking.altara.AltaraPaper;
import games.sparking.altara.game.event.*;
import games.sparking.altara.game.kit.KitManager;
import games.sparking.altara.world.AltaraWorld;
import games.sparking.altara.game.player.GamePlayer;
import games.sparking.altara.game.player.GamePlayerState;
import games.sparking.altara.game.team.GameTeam;
import lombok.Getter;
import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import org.bukkit.event.HandlerList;
import org.bukkit.event.Listener;
import org.bukkit.scheduler.BukkitTask;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.function.Consumer;
import java.util.stream.Collectors;

/**
 * Core abstract class for all game types on the Altara network.
 *
 * <h2>Multiple games, one server</h2>
 * Unlike a traditional single-game-per-server model, the Altara framework allows many
 * {@code Game} instances to run simultaneously on the same server.  Each instance is
 * isolated by its unique {@link #instanceId} and tracked by the {@link GameManager}.
 *
 * <h2>Lifecycle</h2>
 * {@link GameState#PreLoad} → {@link GameState#Loading} → {@link GameState#Recruit}
 * → {@link GameState#Prepare} → {@link GameState#Live} → {@link GameState#End}
 * → {@link GameState#Dead}
 *
 * <h2>Registering a game type</h2>
 * <pre>{@code
 * GameManager.getInstance().registerGameType("mygame", MyGame::new);
 * GameManager.getInstance().createGame("mygame");
 * }</pre>
 */
public abstract class Game implements Listener {

    // =========================================================================
    // Identity
    // =========================================================================

    /** Globally unique identifier for this game instance. */
    @Getter private final UUID instanceId = UUID.randomUUID();

    /**
     * Short 8-character ID for player-facing commands
     * (first 8 hex chars of the UUID, upper-cased).
     */
    @Getter private final String shortId = instanceId.toString().substring(0, 8).toUpperCase();

    // =========================================================================
    // State
    // =========================================================================

    @Getter private GameState state = GameState.PreLoad;

    /** Epoch millis when the game went {@link GameState#Live}, or {@code -1}. */
    @Getter private long startTime = -1;

    /** Epoch millis when the game went {@link GameState#End}, or {@code -1}. */
    @Getter private long endTime = -1;

    // =========================================================================
    // Players & Teams
    // =========================================================================

    /** All players currently in this game, keyed by {@link UUID}. */
    @Getter private final Map<UUID, GamePlayer> players = new ConcurrentHashMap<>();

    /** Teams registered for this game (populated during {@link #onStart()}). */
    @Getter private final List<GameTeam> teams = new ArrayList<>();

    // =========================================================================
    // Internal
    // =========================================================================

    private BukkitTask tickTask;

    /**
     * Manages kit registration, player kit selection, and the kit-selector GUI.
     * Access via {@link #getKitManager()} – it is lazily constructed on first access.
     */
    @Getter private final KitManager kitManager = new KitManager(this);

    /**
     * The loaded arena world for this game instance, if one was loaded via
     * {@link games.sparking.altara.world.MapLoader}.
     *
     * <p>Set this in {@link #onLoad()} once your async map loading completes.
     * Games that don't use dedicated worlds simply leave this {@code null}.
     */
    @Getter @lombok.Setter protected AltaraWorld arenaWorld;

    // =========================================================================
    // Abstract metadata
    // =========================================================================

    public abstract String getName();
    public abstract String getDescription();
    public abstract int getMinPlayers();
    public abstract int getMaxPlayers();

    // =========================================================================
    // Lifecycle hooks
    // =========================================================================

    /** Called on {@link GameState#Loading}. Load world/arena here. */
    protected void onLoad() {}

    /** Called on {@link GameState#Recruit}. Set up lobby behaviours here. */
    protected void onRecruit() {}

    /** Called on {@link GameState#Prepare}. Run countdown, freeze players, etc. */
    protected void onPrepare() {}

    /** Called on {@link GameState#Live}. Give kits, assign teams, start logic. */
    protected abstract void onStart();

    /** Called on {@link GameState#End}. Announce results, schedule cleanup delay. */
    protected abstract void onEnd();

    /** Called on {@link GameState#Dead}. Release extra resources (e.g. delete world). */
    protected void onDead() {}

    /**
     * Called once per server tick while {@link GameState#Live}.
     * Override for continuous game logic (border shrinking, timer checks, etc.).
     */
    protected void onTick() {}

    /** Called after a player successfully joins this game. */
    protected void onPlayerJoin(GamePlayer gamePlayer) {}

    /** Called after a player has been removed from this game. */
    protected void onPlayerLeave(GamePlayer gamePlayer) {}

    // =========================================================================
    // Start condition
    // =========================================================================

    /**
     * Returns {@code true} when the game may transition to {@link GameState#Prepare}.
     * Default: player count >= {@link #getMinPlayers()}.
     */
    public boolean canStart() {
        return players.size() >= getMinPlayers();
    }

    // =========================================================================
    // State management
    // =========================================================================

    /**
     * Transitions the game to {@code newState}.
     * Fires {@link GameStateChangeEvent} first (cancellable).
     */
    public final void setState(GameState newState) {
        GameState oldState = this.state;
        if (oldState == newState) return;

        GameStateChangeEvent event = new GameStateChangeEvent(this, oldState, newState);
        Bukkit.getPluginManager().callEvent(event);
        if (event.isCancelled()) return;

        this.state = newState;

        switch (newState) {
            case Loading -> {
                Bukkit.getPluginManager().registerEvents(this, AltaraPaper.getPaperInstance());
                kitManager.initialize(); // register all kit + perk listeners
                onLoad();
            }
            case Recruit  -> onRecruit();
            case Prepare  -> onPrepare();
            case Live     -> {
                startTime = System.currentTimeMillis();
                onStart();
                Bukkit.getPluginManager().callEvent(new GameStartEvent(this));
                startTickLoop();
            }
            case End      -> {
                endTime = System.currentTimeMillis();
                stopTickLoop();
                onEnd();
                Bukkit.getPluginManager().callEvent(new GameEndEvent(this));
            }
            case Dead     -> {
                stopTickLoop();
                kitManager.cleanup();   // unregister kit + perk listeners
                HandlerList.unregisterAll(this);
                onDead();
                GameManager.getInstance().destroyGame(instanceId);
            }
        }
    }

    /** If {@link GameState#Live}, transitions to {@link GameState#End}. */
    protected final void endGame() {
        if (state == GameState.Live) setState(GameState.End);
    }

    /** Transitions this instance to {@link GameState#Dead}, triggering full cleanup. */
    public final void destroy() {
        if (state != GameState.Dead) setState(GameState.Dead);
    }

    // =========================================================================
    // Tick loop
    // =========================================================================

    private void startTickLoop() {
        if (tickTask != null) return;
        tickTask = Bukkit.getScheduler().runTaskTimer(
                AltaraPaper.getPaperInstance(),
                () -> { if (state == GameState.Live) onTick(); },
                0L, 1L
        );
    }

    private void stopTickLoop() {
        if (tickTask != null) { tickTask.cancel(); tickTask = null; }
    }

    // =========================================================================
    // Player management
    // =========================================================================

    /**
     * Adds a player to this game.
     * Fails if the player is already in a game, this game is full,
     * or a {@link PlayerJoinGameEvent} listener cancels the join.
     *
     * @return {@code true} on success
     */
    public final boolean addPlayer(Player player) {
        if (players.containsKey(player.getUniqueId())) return false;
        if (players.size() >= getMaxPlayers()) return false;
        if (GameManager.getInstance().getPlayerGame(player) != null) return false;

        GamePlayer gamePlayer = new GamePlayer(player, this);

        PlayerJoinGameEvent event = new PlayerJoinGameEvent(this, gamePlayer);
        Bukkit.getPluginManager().callEvent(event);
        if (event.isCancelled()) return false;

        players.put(player.getUniqueId(), gamePlayer);
        GameManager.getInstance().registerPlayerGame(player, this);
        onPlayerJoin(gamePlayer);
        return true;
    }

    /**
     * Removes a player from this game.
     *
     * @return {@code true} if the player was in this game and was removed
     */
    public final boolean removePlayer(Player player) {
        GamePlayer gamePlayer = players.remove(player.getUniqueId());
        if (gamePlayer == null) return false;

        teams.forEach(team -> team.removePlayer(player));
        GameManager.getInstance().unregisterPlayerGame(player);

        Bukkit.getPluginManager().callEvent(new PlayerLeaveGameEvent(this, gamePlayer));
        onPlayerLeave(gamePlayer);
        return true;
    }

    public boolean hasPlayer(Player player) {
        return players.containsKey(player.getUniqueId());
    }

    public Optional<GamePlayer> getGamePlayer(Player player) {
        return Optional.ofNullable(players.get(player.getUniqueId()));
    }

    /** All online players whose state is {@link GamePlayerState#ALIVE}. */
    public List<Player> getAlivePlayers() {
        return players.values().stream()
                .filter(GamePlayer::isAlive)
                .map(GamePlayer::getPlayer)
                .filter(Objects::nonNull)
                .collect(Collectors.toList());
    }

    public long getAliveCount() {
        return players.values().stream().filter(GamePlayer::isAlive).count();
    }

    // =========================================================================
    // Team management
    // =========================================================================

    /** Registers a team and returns it (for chaining). */
    public GameTeam addTeam(GameTeam team) {
        teams.add(team);
        return team;
    }

    public Optional<GameTeam> getTeamOf(Player player) {
        return teams.stream().filter(t -> t.hasPlayer(player)).findFirst();
    }

    // =========================================================================
    // Messaging
    // =========================================================================

    /** Sends a message to every online player in this game. */
    public void broadcast(String message) {
        players.values().forEach(gp -> gp.sendMessage(message));
    }

    public void forEachPlayer(Consumer<GamePlayer> action) {
        players.values().forEach(action);
    }

    // =========================================================================
    // Convenience state queries
    // =========================================================================

    public boolean isLive()       { return state == GameState.Live; }
    public boolean isRecruiting() { return state == GameState.Recruit; }
    public boolean isPreparing()  { return state == GameState.Prepare; }
    public boolean hasEnded()     { return state == GameState.End || state == GameState.Dead; }

    @Override
    public String toString() {
        return getName() + "#" + shortId + "[" + state + ", players=" + players.size() + "]";
    }
}

package games.sparking.altara.game.games.bomblobbers.kit;

import games.sparking.altara.game.games.bomblobbers.BombLobbers;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import org.bukkit.Location;
import org.bukkit.Material;
import org.bukkit.block.Block;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.block.Action;
import org.bukkit.event.player.PlayerInteractEvent;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;

import java.util.ArrayList;
import java.util.List;

/**
 * <b>Waller Kit</b>
 * <ul>
 *   <li>Starts with 3 "Wall Builder" charges (shown as a shovel's damage bar or stack)</li>
 *   <li>Right-click → place a temporary 3-block-wide wall of sandstone in front of you</li>
 *   <li>Each charge places one wall and is consumed on use</li>
 *   <li>Double jump</li>
 * </ul>
 *
 * <p>Walls are tracked and never break other blocks – they are placed only into air.
 */
public class KitWaller extends LobberKit implements Listener {

    private static final int SLOT_SHOVEL = 1;
    /** Number of wall charges given at the start. */
    private static final int STARTING_CHARGES = 3;
    /** Height of each wall (blocks). */
    private static final int WALL_HEIGHT = 3;

    /** Tracks every block placed by this kit so they are never recorded as "natural". */
    private final List<Location> _placedBlocks = new ArrayList<>();

    public KitWaller(BombLobbers game) {
        super(game);
    }

    @Override public String getName() { return "Waller"; }
    @Override public Material getIcon() { return Material.SANDSTONE; }

    @Override
    public String[] getDescription() {
        return new String[]{
                "§7• §a3× Wall Builder charges",
                "§7  §7Right-click shovel §8→ §aplace sandstone wall",
                "§7• §aDouble Jump"
        };
    }

    @Override
    public void apply(Player player) {
        player.getInventory().setItem(SLOT_SHOVEL, makeShovel(STARTING_CHARGES));
        player.setAllowFlight(true);
        player.setFlying(false);
    }

    // -------------------------------------------------------------------------
    // Wall placement
    // -------------------------------------------------------------------------

    @EventHandler
    public void onPlaceWall(PlayerInteractEvent event) {
        Player player = event.getPlayer();
        if (!game.isLive() || !game.hasPlayer(player)) return;
        if (!game.getKitOf(player).equals(this)) return;

        Action action = event.getAction();
        if (action != Action.RIGHT_CLICK_AIR && action != Action.RIGHT_CLICK_BLOCK) return;

        ItemStack shovel = player.getInventory().getItem(SLOT_SHOVEL);
        if (shovel == null || shovel.getType() != Material.WOODEN_SHOVEL) return;

        event.setCancelled(true);

        int charges = shovel.getAmount();
        if (charges <= 0) {
            player.sendActionBar(Component.text("No wall charges remaining!", NamedTextColor.RED));
            return;
        }

        if (!buildWall(player)) {
            player.sendActionBar(Component.text("Not enough space for a wall here!", NamedTextColor.RED));
            return;
        }

        // Consume one charge.
        if (charges == 1) {
            player.getInventory().setItem(SLOT_SHOVEL, new ItemStack(Material.AIR));
        } else {
            player.getInventory().setItem(SLOT_SHOVEL, makeShovel(charges - 1));
        }
        player.updateInventory();
        player.sendActionBar(Component.text("Wall placed! (" + (charges - 1) + " remaining)", NamedTextColor.GREEN));
    }

    /**
     * Builds a {@link #WALL_HEIGHT}-block-tall wall of sandstone directly in front
     * of the player, one block away.  Only places blocks into air.
     *
     * @return {@code true} if at least one block was placed
     */
    private boolean buildWall(Player player) {
        // "Forward" direction snapped to the nearest axis.
        Location base = player.getLocation().add(
                player.getLocation().getDirection().setY(0).normalize().multiply(2.0));
        base.setY(base.getY() - 0.5); // align to floor

        // Perpendicular offset vector to spread the wall left/right.
        var dir = player.getLocation().getDirection().setY(0).normalize();
        var perp = new org.bukkit.util.Vector(-dir.getZ(), 0, dir.getX());

        boolean placed = false;
        for (int y = 0; y < WALL_HEIGHT; y++) {
            for (int side = -1; side <= 1; side++) {
                Location spot = base.clone()
                        .add(perp.clone().multiply(side))
                        .add(0, y, 0);
                Block block = spot.getBlock();
                if (block.getType().isAir()) {
                    block.setType(Material.SANDSTONE);
                    _placedBlocks.add(block.getLocation());
                    placed = true;
                }
            }
        }
        return placed;
    }

    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    private ItemStack makeShovel(int charges) {
        ItemStack item = new ItemStack(Material.WOODEN_SHOVEL, charges);
        ItemMeta meta = item.getItemMeta();
        meta.displayName(Component.text("Wall Builder (" + charges + ")", NamedTextColor.YELLOW));
        meta.lore(List.of(
                Component.text("Right-click to place a sandstone wall", NamedTextColor.GRAY)
        ));
        item.setItemMeta(meta);
        return item;
    }

    /**
     * @return all block locations placed by this kit instance (for cleanup on game end)
     */
    public List<Location> getPlacedBlocks() {
        return _placedBlocks;
    }
}

